for (const [key, values] of Object.entries(CATALOG_ROWS)) {
  if (values.length !== SUPPORTED_LOCALES.length) throw new Error(`Catalog locale count mismatch: ${key}`);
}

export const catalogs = Object.freeze(Object.fromEntries(SUPPORTED_LOCALES.map((locale, index) => [
  locale,
  Object.freeze(Object.fromEntries(Object.entries(CATALOG_ROWS).map(([key, values]) => [key, values[index]])))
])));

export function normalizeLocale(value) {
  const text = String(value ?? "").trim();
  if (LOCALE_INDEX.has(text)) return text;
  const compact = text.replace(/[-_]/g, "").toLowerCase();
  return SUPPORTED_LOCALES.find((locale) => locale.toLowerCase() === compact) ?? DEFAULT_LOCALE;
}

export function readLocale(storage = globalThis.localStorage) {
  return normalizeLocale(storage?.getItem?.(LOCALE_STORAGE_KEY));
}

export function saveLocale(locale, storage = globalThis.localStorage) {
  const normalized = normalizeLocale(locale);
  storage?.setItem?.(LOCALE_STORAGE_KEY, normalized);
  return normalized;
}

export function setLocale(locale, { storage = globalThis.localStorage } = {}) {
  activeLocale = saveLocale(locale, storage);
  return activeLocale;
}

export function currentLocale() {
  return activeLocale;
}

export function escapeHtml(value) {
  return String(value ?? "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

export function t(key, params = {}, locale = activeLocale) {
  return formatMessage(key, params, locale, true);
}

export function tText(key, params = {}, locale = activeLocale) {
  return formatMessage(key, params, locale, false);
}

export function tTextOr(key, fallback, params = {}, locale = activeLocale) {
  const catalog = catalogs[normalizeLocale(locale)] ?? catalogs[DEFAULT_LOCALE];
  if (!Object.hasOwn(catalog, key)) return String(fallback ?? "");
  return formatMessage(key, params, locale, false);
}

export function localizedMessage(key, params = {}) {
  return Object.freeze({ key, params: Object.freeze({ ...params }) });
}

export function resolveLocalizedMessage(value, locale = activeLocale) {
  if (!value || typeof value !== "object" || typeof value.key !== "string") return String(value ?? "");
  return tText(value.key, value.params ?? {}, locale);
}

function formatMessage(key, params, locale, escapeParameters) {
  const message = catalogs[normalizeLocale(locale)]?.[key] ?? catalogs[DEFAULT_LOCALE][key] ?? key;
  return message.replace(/\{([A-Za-z][A-Za-z0-9_]*)\}/g, (_match, name) => {
    const value = Object.hasOwn(params, name) ? params[name] : `{${name}}`;
    return escapeParameters ? escapeHtml(value) : String(value ?? "");
  });
}

export function applyDocumentLocale(ownerDocument = document, locale = activeLocale) {
  const normalized = normalizeLocale(locale);
  ownerDocument.documentElement.lang = DOCUMENT_LANGUAGE_TAGS[normalized];
  for (const element of ownerDocument.querySelectorAll("[data-i18n]")) {
    element.textContent = tText(element.dataset.i18n, {}, normalized);
  }
  for (const element of ownerDocument.querySelectorAll("[data-i18n-placeholder]")) {
    element.placeholder = tText(element.dataset.i18nPlaceholder, {}, normalized);
  }
  for (const element of ownerDocument.querySelectorAll("[data-i18n-title]")) {
    element.title = tText(element.dataset.i18nTitle, {}, normalized);
  }
  for (const element of ownerDocument.querySelectorAll("[data-i18n-aria-label]")) {
    element.setAttribute("aria-label", tText(element.dataset.i18nAriaLabel, {}, normalized));
  }
  ownerDocument.dispatchEvent?.(new CustomEvent("txteditor-locale-changed", { detail: { locale: normalized } }));
}

export function catalogPlaceholderSet(message) {
  return new Set(String(message).match(/\{([A-Za-z][A-Za-z0-9_]*)\}/g)?.map((value) => value.slice(1, -1)) ?? []);
}

export function validateCatalogs(source = catalogs) {
  const keys = Object.keys(source[DEFAULT_LOCALE] ?? {}).sort();
  for (const locale of SUPPORTED_LOCALES) {
    const catalog = source[locale];
    if (!catalog) throw new Error(`Missing locale catalog: ${locale}`);
    const localeKeys = Object.keys(catalog).sort();
    if (localeKeys.join("\u001f") !== keys.join("\u001f")) throw new Error(`Catalog key mismatch: ${locale}`);
    for (const key of keys) {
      const expected = [...catalogPlaceholderSet(source[DEFAULT_LOCALE][key])].sort().join(",");
      const actual = [...catalogPlaceholderSet(catalog[key])].sort().join(",");
      if (expected !== actual) throw new Error(`Catalog placeholder mismatch: ${locale}.${key}`);
    }
    if (locale !== DEFAULT_LOCALE && JSON.stringify(catalog) === JSON.stringify(source[DEFAULT_LOCALE])) {
      throw new Error(`Locale catalog must not duplicate enUS: ${locale}`);
    }
  }
  return { keys: keys.length, locales: SUPPORTED_LOCALES.length };
}

export const catalogValidation = validateCatalogs();
